	, #{ickey}
	, #{minexpirestd}
	, #{safestockyn}
	, #{pltboxdeligbcd}
	, #{pltdeligbcd}
	, #{wrappedyn}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

